#!/bin/bash
BASE64_STR=""
echo "$BASE64_STR" | base64 -d > /tmp/test-repo/device.mk
sed -i '' 's/sysupgrade\.itb/sysupgrade.bin/g' /tmp/test-repo/device.mk
NEW_BASE64=$(cat /tmp/test-repo/device.mk | base64)
# 替换 workflow 里的 base64 字符串
sed -i '' "s|$BASE64_STR|$NEW_BASE64|g" /tmp/test-repo/.github/workflows/build-n30pro.yml
